    int max_ones_row = -1;
    int max_ones = -1;
    for(int i = 0; i < m; i++) {
        int ones = 0;
        for(int j = 0; j < n; j++) {
            int val;
            cin >> val;
            if(val == 1) ones++;
        }
        if(ones > max_ones) {
            max_ones = ones;
            max_ones_row = i;
        }
    }
    cout << max_ones_row << endl;
    return 0;
}
